const OBS = 'http://host.docker.internal:27123';
const KEY = $env.OBSIDIAN_API_KEY;
const TWIY = $env.TWIY_API_URL;
const WH = $env.TWIY_WEBHOOK_KEY;
const ROOT = '02-Projets';

const STATUTS = new Set(['a_faire', 'en_cours', 'fait', 'abandonne']);
const TYPES = new Set(['dev', 'beatmaker', 'croisement', 'freelance', 'routine']);
const STATUT_ALIAS = {
  a_faire: 'a_faire', todo: 'a_faire', 'à_faire': 'a_faire',
  en_cours: 'en_cours', doing: 'en_cours', wip: 'en_cours',
  fait: 'fait', done: 'fait', shippe: 'fait', shippé: 'fait',
  abandonne: 'abandonne', abandoned: 'abandonne',
};

async function listDir(rel) {
  const url = `${OBS}/vault/${rel.replace(/^\/+|\/+$/g, '')}/`;
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { Authorization: `Bearer ${KEY}` },
    json: true,
  });
  return Array.isArray(data?.files) ? data.files : [];
}

async function readNote(relPath) {
  const url = `${OBS}/vault/${relPath.replace(/^\/+/, '')}`;
  return await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      Authorization: `Bearer ${KEY}`,
      Accept: 'text/markdown',
    },
    encoding: 'text',
  });
}

function parseFrontmatter(raw) {
  const text = typeof raw === 'string' ? raw : (raw?.data ?? raw?.content ?? String(raw ?? ''));
  const m = text.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!m) return { frontmatter: {} };
  const fm = {};
  for (const line of m[1].split(/\r?\n/)) {
    const i = line.indexOf(':');
    if (i <= 0) continue;
    const k = line.slice(0, i).trim();
    let v = line.slice(i + 1).trim();
    if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
      v = v.slice(1, -1);
    }
    fm[k] = v;
  }
  return { frontmatter: fm };
}

function mapStatut(v) {
  if (v == null || v === '') return undefined;
  const key = String(v).trim().toLowerCase().replace(/\s+/g, '_');
  const mapped = STATUT_ALIAS[key] || key;
  return STATUTS.has(mapped) ? mapped : undefined;
}

function mapType(v) {
  if (v == null || v === '') return 'dev';
  const key = String(v).trim().toLowerCase();
  return TYPES.has(key) ? key : 'dev';
}

if (!KEY) {
  return [{ json: { upsert: false, error: 'OBSIDIAN_API_KEY manquante' } }];
}
if (!TWIY || !WH) {
  return [{ json: { upsert: false, error: 'TWIY_API_URL ou TWIY_WEBHOOK_KEY manquant' } }];
}

const listJson = $input.first().json;
const topFiles = Array.isArray(listJson?.files) ? listJson.files : [];

const mdPaths = [];
for (const name of topFiles) {
  if (name.endsWith('/')) {
    const sub = `${ROOT}/${name.replace(/\/$/, '')}`;
    try {
      const nested = await listDir(sub);
      for (const f of nested) {
        if (f.endsWith('.md')) mdPaths.push(`${sub}/${f}`);
      }
    } catch {
      // ignore sous-dossier
    }
  } else if (name.endsWith('.md')) {
    mdPaths.push(`${ROOT}/${name}`);
  }
}

let existing = [];
try {
  const q = await this.helpers.httpRequest({
    method: 'GET',
    url: `${TWIY}/quetes`,
    headers: { 'x-api-key': WH },
    json: true,
  });
  if (Array.isArray(q)) existing = q;
  else if (Array.isArray(q?.data)) existing = q.data;
} catch {
  existing = [];
}

const byLien = new Map();
for (const q of existing) {
  if (q?.lien_note_obsidian) byLien.set(String(q.lien_note_obsidian), q);
}

const out = [];
for (const rel of mdPaths) {
  let raw;
  try {
    raw = await readNote(rel);
  } catch (e) {
    out.push({ json: { upsert: false, path: rel, error: String(e.message || e) } });
    continue;
  }
  const { frontmatter: fm } = parseFrontmatter(raw);
  const baseName = rel.split('/').pop().replace(/\.md$/i, '');
  const titre = String(fm.titre || fm.title || baseName).trim();
  if (!titre) {
    out.push({ json: { upsert: false, path: rel, error: 'titre manquant' } });
    continue;
  }
  const payload = {
    type: mapType(fm.type || fm.arc || fm.domaine),
    titre,
    lien_note_obsidian: rel,
  };
  const statut = mapStatut(fm.statut || fm.status || fm.etat);
  if (statut) payload.statut = statut;

  const prev = byLien.get(rel) || byLien.get(baseName) || byLien.get(`${baseName}.md`);
  if (prev?.id) {
    out.push({
      json: {
        upsert: true,
        mode: 'patch',
        id: prev.id,
        path: rel,
        body: {
          titre: payload.titre,
          ...(payload.statut ? { statut: payload.statut } : {}),
          lien_note_obsidian: rel,
        },
      },
    });
  } else {
    out.push({
      json: {
        upsert: true,
        mode: 'post',
        path: rel,
        body: payload,
      },
    });
  }
}

if (!out.length) {
  return [{ json: { upsert: false, reason: 'aucun .md dans 02-Projets', filesSeen: topFiles } }];
}
return out;
